class Solution:
    def findMaximumXOR(self, nums):
        # independent: brute force all pairs (small/medium n via stress kept feasible).
        best = 0
        n = len(nums)
        for i in range(n):
            a = nums[i]
            for j in range(i + 1, n):
                v = a ^ nums[j]
                if v > best:
                    best = v
        return best

solutions.python:
class Solution:
    def findMaximumXOR(self, nums):
        ans = 0
        mask = 0
        for bit in range(31, -1, -1):
            mask |= (1 << bit)
            prefixes = {x & mask for x in nums}
            candidate = ans | (1 << bit)
            for p in prefixes:
                if (candidate ^ p) in prefixes:
                    ans = candidate
                    break
        return ans

