var findMaximumXOR = function(nums) {
    let ans = 0, mask = 0;
    for (let bit = 31; bit >= 0; bit--) {
        mask |= (1 << bit);
        const prefixes = new Set();
        for (const x of nums) prefixes.add((x & mask) >>> 0);
        const candidate = (ans | (1 << bit)) >>> 0;
        for (const p of prefixes) {
            if (prefixes.has((candidate ^ p) >>> 0)) {
                ans = candidate;
                break;
            }
        }
    }
    return ans;
};
